let timelineUpdateScheduled=!1;function requestTimelineUpdate(){timelineUpdateScheduled||(timelineUpdateScheduled=!0,requestAnimationFrame(()=>{timelineUpdateScheduled=!1,updateTimeline()}))}function updateTimeline(){let e=document.getElementById("timelineCanvas");if(!e)return;let t=e.offsetWidth,a=e.offsetHeight;if(0===t||0===a)return;e.width=t,e.height=a;let l=e.getContext("2d");l.clearRect(0,0,t,a);let n=state.pageCount,i=state.tracks,o=a/Math.max(i.length,1),d=t/n;for(let e=0;e<n;e++){let t=e*d;for(let a=0;a<i.length;a++){let n=i[a],g=a*o,s=getPageSteps(n,e),r=d/state.stepCount;for(let e=0;e<state.stepCount;e++){let a=s[e];if(a&&a.gate){let i=.55+.45*(a.velocity/127);l.fillStyle=n.color,l.globalAlpha=i,l.fillRect(t+e*r+.5,g+1,Math.max(r-1,1),o-2)}}}}l.globalAlpha=1,l.strokeStyle="rgba(255,255,255,0.07)",l.lineWidth=1;for(let e=1;e<n;e++){let t=Math.round(e*d);l.beginPath(),l.moveTo(t,0),l.lineTo(t,a),l.stroke()}let g=state.viewPage*d;if(l.strokeStyle="rgba(240,240,240,0.9)",l.lineWidth=2,l.strokeRect(g+1,1,d-2,a-2),state.playing&&state.currentPage!==state.viewPage){let e=state.currentPage*d;l.strokeStyle="rgba(255,56,100,0.7)",l.lineWidth=1.5,l.strokeRect(e+1.5,1.5,d-3,a-3)}document.getElementById("btnPagePrev").disabled=0===state.viewPage,document.getElementById("btnPageNext").disabled=state.viewPage>=state.pageCount-1&&state.pageCount>=MAX_PAGES}document.getElementById("timelineCanvas").addEventListener("click",e=>{let t=document.getElementById("timelineCanvas"),a=t.getBoundingClientRect(),l=Math.floor((e.clientX-a.left)/(t.offsetWidth/state.pageCount));l>=0&&l<state.pageCount&&navigateToPage(l)});